class Solution:
    def countGoodTriplets(self, arr, a, b, c):
        import itertools
        count = 0
        for i, j, k in itertools.combinations(range(len(arr)), 3):
            if abs(arr[i] - arr[j]) <= a and abs(arr[j] - arr[k]) <= b and abs(arr[i] - arr[k]) <= c:
                count += 1
        return count

